$SSH 'echo "===== login.defs (PASS_*) ====="; sudo -n cat /etc/login.defs 2>&1 | grep -Ei "^\s*PASS_|^\s*ENCRYPT_METHOD|^\s*SHA_CRYPT|^\s*LOGIN_RETRIES|^\s*UMASK" ;
echo; echo "===== ls /etc/pam.d ====="; ls -la /etc/pam.d/ 2>&1;
echo; echo "===== common-password ====="; cat /etc/pam.d/common-password 2>&1;
