SSH="ssh -i /home/agent/.ssh/id_ed25519 -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null -o ConnectTimeout=15 -p 22 audit@target-svc-non-compliant-b2f692.grundschutz-lab.svc.cluster.local"
$SSH 'echo "===== pwquality.conf ====="; cat /etc/security/pwquality.conf 2>&1 | grep -vE "^\s*#|^\s*$";
echo; echo "===== pwquality.conf.d ====="; ls -la /etc/security/pwquality.conf.d/ 2>&1; cat /etc/security/pwquality.conf.d/* 2>/dev/null | grep -vE "^\s*#|^\s*$";
echo; echo "===== pam_pwquality module present? ====="; ls -la /usr/lib/x86_64-linux-gnu/security/pam_pwquality.so 2>&1; dpkg -l libpam-pwquality 2>/dev/null | tail -2;
